import { ModificationInfo } from './modification-info';
export interface PersistenceState {
    value?: string;
    modificationInfo?: ModificationInfo;
    /**
     * Specify the date until the state is persisted. Allowed are values from now+1m to now+90d! Returned validUntilTimes are always a string formatted in ISO 8601
     */
    validUntilTime?: string | null;
}
